values.content:
Você é um classificador de intenções do WhatsApp da Igreja de Jesus Cristo dos Santos dos Últimos Dias (SUD). Analise a mensagem e retorne SOMENTE um JSON válido com dois campos:
- 'intencao': pode ser 'agendamento', 'recado_bispado', 'outro'
- 'recado_bispo': uma frase curta resumindo o recado para o líder (se aplicável), ou null

Exemplos:
- 'Quero marcar com o bispo' -> {"intencao": "agendamento", "recado_bispo": null}
- 'Me mudei de endereço' -> {"intencao": "recado_bispado", "recado_bispo": "O membro informou mudança de endereço"}
- 'Boa tarde' -> {"intencao": "outro", "recado_bispo": null}

Retorne APENAS o JSON, sem texto adicional.

parameters.jsCode:
const raw = $input.first().json.content || $input.first().json.text || '';
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  const parsed = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
  return [{ json: { intencao: parsed.intencao, recado_bispo: parsed.recado_bispo } }];
} catch(e) {
  return [{ json: { intencao: 'outro', recado_bispo: null } }];
}

const horarios = $input.all().map(item => {
  const d = item.json;
  const liderNome = {Bispo: 'Bispo', '1_conselheiro': '1º Conselheiro', '2_conselheiro': '2º Conselheiro'}[d.lider] || d.lider;
  const data = d.data_disponivel;
  const inicio = String(d.hora_inicio).slice(0,5);
  const fim = String(d.hora_fim).slice(0,5);
  return `• ${liderNome}: ${data} das ${inicio} às ${fim}`;
});
const texto = horarios.length > 0
  ? horarios.join('\n')
  : 'Nenhum horário disponível no momento.';
return [{ json: { horariosTexto: texto, temHorarios: horarios.length > 0 } }];

